import { useEffect, useMemo, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { supabase } from '../../../supabase/client';
import { accessGate } from '../services/accessGate';
import FeedbackFab from '../../../components/ui/FeedbackFab';
import { track, trackPage } from "../../telemetry/track";

function getNext(search: string) {
    const params = new URLSearchParams(search);
    const next = params.get('next');
    return next && next.startsWith('/') ? next : '/';
}

export default function AccessGatePage() {
    const nav = useNavigate();
    const loc = useLocation();

    const nextPath = useMemo(() => getNext(loc.search), [loc.search]);

    useEffect(() => {
        trackPage("access_gate", { next: nextPath });
    }, [nextPath]);

    const [code, setCode] = useState('');
    const [loading, setLoading] = useState(false);
    const [err, setErr] = useState<string | null>(null);

    const daysValid = Number(import.meta.env.VITE_ACCESS_GATE_DAYS_VALID ?? '30');

    useEffect(() => {
        if (accessGate.isEnabled() && accessGate.hasAccess()) {
            nav(nextPath, { replace: true });
        }
    }, [nextPath, nav]);

    const submit = async (e: React.FormEvent) => {
        e.preventDefault();
        setErr(null);

        const normalized = code.trim().toUpperCase();
        if (!normalized) {
            track("access_gate_submit_missing_code", "warn");
            setErr('Ingresa tu código.');
            return;
        }

        track("access_gate_submit", "info", { code_len: normalized.length, next: nextPath });
        setLoading(true);
        try {
            // 1) Validar en modo anon (NO consumir / NO claim)
            const { data: isValid, error: vErr } = await (supabase as any).rpc('validate_invitation', {
                p_code: normalized,
            });
            if (vErr) throw vErr;

            if (!isValid) {
                track("access_gate_code_invalid", "warn", { code_len: normalized.length, next: nextPath });
                setErr('Ese código ya venció o no existe. Pide uno nuevo.');
                return;
            }

            // 2) Guardar pase local para permitir navegar el piloto (sin quemar el código)
            accessGate.grant(`CODE:${normalized}`, Number.isFinite(daysValid) ? daysValid : 30);
            track("access_gate_granted_local", "info", { days_valid: daysValid, next: nextPath });

            // 3) Entrar
            nav(nextPath, { replace: true });
        } catch (e: any) {
            track("access_gate_error", "error", { message: String(e?.message || "unknown").slice(0, 160) });
            setErr(e?.message ?? 'Ese código no calza. Revisa y prueba de nuevo.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-white flex items-center justify-center px-4">
            <div className="w-full max-w-md">
                <div className="bg-white border border-slate-200 rounded-3xl p-8 shadow-xl shadow-slate-200/50 transition-shadow hover:shadow-2xl hover:shadow-slate-200/60">
                    <h1 className="text-xl font-black text-slate-900">Acceso por invitación</h1>
                    <p className="text-sm text-slate-500 font-medium mt-1">
                        Si tienes código, entra. Si no, comunícate con un administrador.
                    </p>

                    <form onSubmit={submit} className="space-y-4 mt-6">
                        <div>
                            <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">
                                Código de invitación
                            </label>
                            <input
                                value={code}
                                onChange={(e) => setCode(e.target.value)}
                                placeholder="Ej: OPINA-7F3K"
                                className="w-full mt-2 px-4 py-3 rounded-xl border border-slate-200 focus:border-primary-500 focus:ring-4 focus:ring-primary-500/10 outline-none transition-all font-bold text-slate-900 uppercase"
                                autoFocus
                            />
                            <p className="text-[11px] text-slate-500 mt-2 font-medium">Respeta mayúsculas y guiones.</p>
                            {err && <p className="text-sm text-red-600 mt-2 font-medium">{err}</p>}
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-3.5 rounded-xl bg-primary hover:opacity-90 text-white font-black transition-all disabled:opacity-50 shadow-sm"
                        >
                            {loading ? 'Verificando código…' : 'Entrar'}
                        </button>

                        {/* Admin bypass (visible para todos, valida rol en el click) */}
                        <div className="mt-4 border-t border-slate-100 pt-4">
                            <button
                                type="button"
                                onClick={async () => {
                                    try {
                                        // Validar primero si hay una sesión activa real de Supabase
                                        const { data: { user: currentUser } } = await supabase.auth.getUser();

                                        if (!currentUser || currentUser.is_anonymous) {
                                            nav('/admin-login');
                                            return;
                                        }

                                        // Requiere que exista tabla users con role y que el usuario ya esté autenticado
                                        const { data, error } = await supabase
                                            .from("users")
                                            .select("role")
                                            .eq("user_id", currentUser.id)
                                            .single();

                                        if (error) {
                                            nav('/admin-login');
                                            return;
                                        }

                                        if ((data as any)?.role === "admin") {
                                            track("access_gate_admin_bypass", "info");
                                            localStorage.setItem("opina_access_pass", "admin");
                                            window.location.href = "/";
                                        } else {
                                            nav('/admin-login');
                                        }
                                    } catch (err) {
                                        nav('/admin-login');
                                    }
                                }}
                                className="w-full flex items-center justify-center gap-2 rounded-xl border border-slate-200 bg-white px-4 py-3 text-sm font-bold text-slate-600 hover:bg-slate-50 hover:text-primary-600 hover:border-primary-200 transition-all shadow-sm"
                            >
                                <span className="material-symbols-outlined text-sm">shield_person</span>
                                Ingreso Administrador
                            </button>
                        </div>
                    </form>
                </div>

                {/* Helper text de invitación en vez de tag piloto */}
                <div className="mt-8 flex flex-col items-center gap-3">
                    <p className="text-[11px] font-medium text-slate-500">
                        ¿Necesitas un código? Pídelo a quien te invitó.
                    </p>
                    <button
                        onClick={() => nav('/')}
                        className="text-[12px] font-bold text-slate-400 hover:text-primary-600 transition-colors uppercase tracking-wider"
                    >
                        Volver al inicio
                    </button>
                </div>
            </div>
            <FeedbackFab />
        </div>
    );
}

import { Plus, Trash2 } from "lucide-react";
import { TopicQuestion, QuestionType } from "../../signals/types/actualidad";

interface EditorPreguntasProps {
    questions: TopicQuestion[];
    handleQuestionChange: (orderIdx: number, field: string, value: any) => void;
    handleQuestionOptionAdd: (orderIdx: number) => void;
    handleQuestionOptionChange: (orderIdx: number, optIdx: number, value: string) => void;
    handleQuestionOptionRemove: (orderIdx: number, optIdx: number) => void;
}

export function EditorPreguntas({
    questions,
    handleQuestionChange,
    handleQuestionOptionAdd,
    handleQuestionOptionChange,
    handleQuestionOptionRemove
}: EditorPreguntasProps) {
    const titles = [
        "1. Postura de Entrada",
        "2. Diagnóstico / Interpretación",
        "3. Sentencia Final / Política"
    ];

    return (
        <section className="bg-white rounded-2xl shadow-sm border border-slate-200/60 p-6 lg:p-8">
            <div className="mb-6 flex items-center justify-between border-b border-slate-100 pb-4">
                <div>
                    <h2 className="text-lg font-black text-slate-900">3. Embudo Evaluativo Estricto</h2>
                    <p className="text-xs text-slate-500">Diseña las 3 preguntas consecutivas necesarias para capturar la señal completa.</p>
                </div>
                <div className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-bold">
                    Regla de 3 Estricta Activa
                </div>
            </div>

            <div className="space-y-6">
                {questions.map((q, idx) => (
                    <div key={idx} className="bg-slate-50 border border-slate-200 rounded-2xl p-5 relative">
                        <div className="flex flex-col md:flex-row gap-5">
                            <div className="absolute -left-3 -top-3 w-8 h-8 bg-slate-800 text-white rounded-full flex justify-center items-center shadow-sm font-black text-sm border-2 border-white">
                                {idx + 1}
                            </div>

                            <div className="flex-1 pl-2">
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">
                                    {titles[idx]}
                                </label>
                                <input
                                    type="text"
                                    value={q.text || ""}
                                    onChange={e => handleQuestionChange(idx, 'text', e.target.value)}
                                    className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-primary-500 outline-none font-bold text-slate-800 text-base shadow-sm"
                                    placeholder="Ej: ¿Qué tan de acuerdo estás con..."
                                />
                            </div>

                            <div className="w-full md:w-56">
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">
                                    Formato de Captura
                                </label>
                                <select
                                    value={q.type || 'single_choice'}
                                    onChange={e => handleQuestionChange(idx, 'type', e.target.value as QuestionType)}
                                    className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-primary-500 outline-none font-bold text-sm text-slate-700 shadow-sm"
                                >
                                    <option value="scale_0_10">Escala 0-10</option>
                                    <option value="scale_5">Escala de 5 (Likert)</option>
                                    <option value="single_choice">Múltiple Opción</option>
                                    <option value="single_choice_polar">Opciones Polarizadas</option>
                                    <option value="yes_no">Botonera Sí / No</option>
                                </select>
                            </div>
                        </div>

                        {(q.type === 'single_choice' || q.type === 'single_choice_polar') && (
                            <div className="mt-4 pt-4 border-t border-slate-200 pl-2">
                                <div className="flex justify-between items-center mb-3">
                                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">
                                        Opciones de Respuesta
                                    </label>
                                    <button
                                        onClick={() => handleQuestionOptionAdd(idx)}
                                        className="text-xs font-bold text-primary-600 bg-primary-50 px-3 py-1.5 rounded-lg flex items-center gap-1 hover:bg-primary-100"
                                    >
                                        <Plus className="w-3 h-3" /> Añadir
                                    </button>
                                </div>
                                <div className="space-y-2">
                                    {q.options?.map((opt, oIdx) => (
                                        <div key={oIdx} className="flex gap-2 items-center">
                                            <div className="w-6 text-center text-xs font-bold text-slate-300">
                                                {String.fromCharCode(65 + oIdx)}
                                            </div>
                                            <input
                                                type="text"
                                                value={opt || ""}
                                                onChange={e => handleQuestionOptionChange(idx, oIdx, e.target.value)}
                                                className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none text-sm font-medium"
                                                placeholder="Valor de la alternativa..."
                                            />
                                            <button
                                                onClick={() => handleQuestionOptionRemove(idx, oIdx)}
                                                className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {q.type === 'yes_no' && (
                            <div className="mt-4 pt-4 border-t border-slate-200 pl-2">
                                <div className="flex gap-3">
                                    <div className="px-4 py-2 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-xl text-sm font-bold shadow-sm">Sí / A Favor</div>
                                    <div className="px-4 py-2 bg-red-50 text-red-700 border border-red-200 rounded-xl text-sm font-bold shadow-sm">No / En Contra</div>
                                </div>
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </section>
    );
}

import { InviteRow } from '../services/adminInvitesService';

interface InvitesTableProps {
    sortedInvites: InviteRow[];
    selectedInvites: Set<string>;
    toggleSelectAll: () => void;
    toggleSelect: (id: string) => void;
    handleSort: (key: keyof InviteRow) => void;
    sortConfig: { key: keyof InviteRow; direction: 'asc' | 'desc' } | null;
    waDrafts: Record<string, { phone: string; isSending: boolean; statusMsg?: string }>;
    updateWaDraft: (id: string, updates: Partial<{ phone: string; isSending: boolean; statusMsg?: string }>) => void;
    handleSendWhatsApp: (invite: InviteRow) => void;
    confirmRowAction: { id: string, action: 'active' | 'revoked' | 'delete' } | null;
    setConfirmRowAction: (action: { id: string, action: 'active' | 'revoked' | 'delete' } | null) => void;
    handleStatusChange: (inviteId: string, currentStatus: string, action: 'revoked' | 'active' | 'delete') => void;
    loading: boolean;
}

export function InvitesTable({
    sortedInvites, selectedInvites, toggleSelectAll, toggleSelect,
    handleSort, sortConfig, waDrafts, updateWaDraft, handleSendWhatsApp,
    confirmRowAction, setConfirmRowAction, handleStatusChange, loading
}: InvitesTableProps) {

    const renderSortIcon = (key: keyof InviteRow) => {
        if (sortConfig?.key !== key) return <span className="text-slate-300 ml-1 text-[12px]">↕</span>;
        return sortConfig.direction === 'asc' 
            ? <span className="text-cyan-600 ml-1 text-[12px] font-bold">↑</span> 
            : <span className="text-cyan-600 ml-1 text-[12px] font-bold">↓</span>;
    };

    return (
        <table className="w-full text-sm text-left">
            <thead className="text-[10px] md:text-xs text-slate-500 uppercase tracking-wider bg-slate-50/50">
                <tr>
                    <th className="px-2 py-3 font-bold rounded-tl-xl w-8 text-center">
                        <input
                            type="checkbox"
                            className="w-4 h-4 rounded border-slate-300 text-cyan-600 focus:ring-cyan-500 cursor-pointer"
                            checked={sortedInvites.length > 0 && selectedInvites.size === sortedInvites.length}
                            onChange={toggleSelectAll}
                        />
                    </th>
                    <th className="px-1 py-3 w-6 text-center"></th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('code')}>
                        <div className="flex items-center justify-center whitespace-nowrap">Código {renderSortIcon('code')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('used_by_nickname')}>
                        <div className="flex items-center justify-center">Alias {renderSortIcon('used_by_nickname')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('status')}>
                        <div className="flex items-center justify-center">Estado {renderSortIcon('status')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('expires_at')}>
                        <div className="flex items-center justify-center whitespace-nowrap">Expira {renderSortIcon('expires_at')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('last_active_at')}>
                        <div className="flex items-center justify-center">Última Conexión {renderSortIcon('last_active_at')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('total_sessions')}>
                        <div className="flex items-center justify-center">Sesiones {renderSortIcon('total_sessions')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('total_interactions')}>
                        <div className="flex items-center justify-center">Señales {renderSortIcon('total_interactions')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold cursor-pointer hover:bg-slate-200 transition-colors select-none" onClick={() => handleSort('total_time_spent_seconds')}>
                        <div className="flex items-center justify-center">Minutos {renderSortIcon('total_time_spent_seconds')}</div>
                    </th>
                    <th className="px-2 py-3 font-bold text-center">WhatsApp</th>
                    <th className="px-2 py-3 font-bold rounded-tr-xl whitespace-nowrap text-center w-24">Acciones</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {sortedInvites.length === 0 ? (
                    <tr>
                        <td colSpan={12} className="px-4 py-8 text-center text-slate-500 italic">No hay invitaciones registradas.</td>
                    </tr>
                ) : (
                    sortedInvites.map((invite) => (
                        <tr key={invite.id} className={`hover:bg-slate-50/50 transition-colors ${selectedInvites.has(invite.id) ? 'bg-cyan-50/30' : ''}`}>
                            <td className="px-2 py-3 text-center">
                                <input
                                    type="checkbox"
                                    className="w-4 h-4 rounded border-slate-300 text-cyan-600 focus:ring-cyan-500 cursor-pointer"
                                    checked={selectedInvites.has(invite.id)}
                                    onChange={() => toggleSelect(invite.id)}
                                />
                            </td>
                            <td className="px-1 py-3 text-center">
                                <div
                                    className={`w-2 h-2 rounded-full mx-auto ${invite.used_by_user_id
                                        ? (invite.last_active_at && (Date.now() - new Date(invite.last_active_at).getTime()) < 5 * 60 * 1000)
                                            ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.8)]'
                                            : 'bg-red-500 bg-opacity-80'
                                        : 'bg-slate-200'
                                        }`}
                                    title={invite.used_by_user_id ? (invite.last_active_at && (Date.now() - new Date(invite.last_active_at).getTime()) < 5 * 60 * 1000 ? `Online` : 'Offline') : 'No usada'}
                                />
                            </td>
                            <td className="px-2 py-3 font-mono font-medium text-slate-900 whitespace-nowrap text-[11px] lg:text-sm text-center">{invite.code}</td>
                            <td className="px-2 py-3 text-slate-600 text-center text-[11px] lg:text-xs">
                                {invite.used_by_nickname ? (
                                    <span className="font-bold text-primary-600">{invite.used_by_nickname}</span>
                                ) : (
                                    '-'
                                )}
                            </td>
                            <td className="px-2 py-3 text-center">
                                <span className={`inline-flex items-center px-1.5 py-0.5 rounded-full text-[10px] font-bold ${invite.status === 'active' ? 'bg-emerald-100 text-emerald-800' :
                                    invite.status === 'used' ? 'bg-cyan-100 text-cyan-800' :
                                        invite.status === 'revoked' ? 'bg-red-100 text-red-800' :
                                            'bg-slate-100 text-slate-800'
                                    }`}>
                                    {invite.status.toUpperCase()}
                                </span>
                            </td>
                            <td className="px-2 py-3 text-slate-500 text-[10px] md:text-xs whitespace-nowrap text-center">
                                {invite.expires_at ? new Date(invite.expires_at).toLocaleString('es-ES', { day: '2-digit', month: '2-digit', year: '2-digit', hour: '2-digit', minute: '2-digit' }) : 'Nunca'}
                            </td>
                            <td className="px-2 py-3 text-center">
                                <span className="font-mono text-[10px] md:text-xs text-slate-500">
                                    {invite.last_active_at ? new Date(invite.last_active_at).toLocaleString('es-ES', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : '-'}
                                </span>
                            </td>
                            <td className="px-2 py-3 text-center">
                                <span className="font-mono text-[11px] md:text-sm font-bold text-slate-700">{invite.total_sessions ?? '-'}</span>
                            </td>
                            <td className="px-2 py-3 text-center">
                                <span className="font-mono text-[11px] md:text-sm font-bold text-slate-700">{invite.total_interactions ?? '-'}</span>
                            </td>
                            <td className="px-2 py-3 text-center">
                                <span className="font-mono text-[11px] md:text-sm font-bold text-slate-700">
                                    {invite.total_time_spent_seconds ? (invite.total_time_spent_seconds / 60).toFixed(1) : '-'}
                                </span>
                            </td>
                            <td className="px-2 py-3">
                                <div className="flex items-center justify-center gap-2">
                                    <div className="flex gap-1 w-[130px] shrink-0">
                                        <input
                                            type="text"
                                            placeholder="+569..."
                                            value={waDrafts[invite.id]?.phone ?? invite.whatsapp_phone ?? ''}
                                            onChange={(e) => updateWaDraft(invite.id, { phone: e.target.value })}
                                            className="w-full text-[10px] px-2 py-1 border rounded-lg focus:ring-1 focus:ring-cyan-500 outline-none"
                                            disabled={waDrafts[invite.id]?.isSending}
                                        />
                                        <button
                                            onClick={() => handleSendWhatsApp(invite)}
                                            disabled={waDrafts[invite.id]?.isSending || !(waDrafts[invite.id]?.phone || invite.whatsapp_phone)}
                                            className="bg-emerald-500 text-white rounded-lg p-1 hover:bg-emerald-600 disabled:opacity-50 transition-colors flex items-center justify-center shrink-0"
                                            title="Enviar invitación por WhatsApp"
                                        >
                                            {waDrafts[invite.id]?.isSending ? (
                                                <span className="animate-spin text-[14px] material-symbols-outlined">sync</span>
                                            ) : (
                                                <span className="text-[14px] material-symbols-outlined">send</span>
                                            )}
                                        </button>
                                    </div>
                                    <div className="text-[9px] flex items-center gap-1 text-left w-[80px] shrink-0">
                                        {(waDrafts[invite.id]?.statusMsg || invite.whatsapp_status) && (
                                            <>
                                                <span className={`font-bold whitespace-nowrap ${waDrafts[invite.id]?.statusMsg?.includes('Error') || invite.whatsapp_status === 'error' ? 'text-red-500' : 'text-emerald-600'
                                                    }`}>
                                                    {waDrafts[invite.id]?.statusMsg || (invite.whatsapp_status === 'sent' ? 'Enviado ✅' : invite.whatsapp_status)}
                                                </span>
                                                {invite.whatsapp_error && (
                                                    <span className="text-red-400 truncate max-w-[80px]" title={invite.whatsapp_error}>
                                                        ({invite.whatsapp_error})
                                                    </span>
                                                )}
                                            </>
                                        )}
                                    </div>
                                </div>
                            </td>
                            <td className="px-2 py-3 text-center whitespace-nowrap">
                                {confirmRowAction?.id === invite.id ? (
                                    <div className="flex items-center justify-center gap-1.5 animate-in fade-in zoom-in-95">
                                        <span className="text-[9px] font-bold text-slate-500 uppercase hidden sm:inline">
                                            ¿Seguro?
                                        </span>
                                        <button
                                            onClick={() => setConfirmRowAction(null)}
                                            disabled={loading}
                                            className="px-1.5 py-0.5 rounded text-[10px] font-bold text-slate-500 bg-slate-100 hover:bg-slate-200"
                                        >
                                            NO
                                        </button>
                                        <button
                                            onClick={() => handleStatusChange(invite.id, invite.status, confirmRowAction.action as any)}
                                            disabled={loading}
                                            className={`px-1.5 py-0.5 rounded text-[10px] font-bold text-white ${confirmRowAction.action === 'delete' ? 'bg-red-600 hover:bg-red-700' :
                                                confirmRowAction.action === 'revoked' ? 'bg-blue-600 hover:bg-blue-700' :
                                                    'bg-emerald-600 hover:bg-emerald-700'
                                                }`}
                                        >
                                            SÍ
                                        </button>
                                    </div>
                                ) : (
                                    <div className="flex items-center justify-center gap-1 flex-nowrap">
                                        {invite.status !== 'revoked' && (
                                            <button
                                                onClick={() => setConfirmRowAction({ id: invite.id, action: 'revoked' })}
                                                disabled={loading}
                                                className="text-[10px] font-bold text-red-600 hover:text-red-700 disabled:opacity-50 focus:outline-none rounded px-1"
                                            >
                                                REVOCAR
                                            </button>
                                        )}
                                        {invite.status === 'revoked' && (
                                            <button
                                                onClick={() => handleStatusChange(invite.id, invite.status, 'active')}
                                                disabled={loading}
                                                className="text-[10px] font-bold text-emerald-600 hover:text-emerald-700 disabled:opacity-50 focus:outline-none rounded px-1"
                                            >
                                                REACTIVAR
                                            </button>
                                        )}
                                        <button
                                            onClick={() => setConfirmRowAction({ id: invite.id, action: 'delete' })}
                                            disabled={loading}
                                            className="text-slate-400 hover:text-red-600 disabled:opacity-50 focus:outline-none rounded px-1 flex items-center justify-center"
                                            title="Eliminar permanentemente"
                                        >
                                            <span className="material-symbols-outlined text-[15px]">delete</span>
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </tbody>
        </table>
    );
}

import { useState, useCallback, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Topic, TopicQuestion, TopicStatus, QuestionType } from "../../signals/types/actualidad";
import { adminActualidadService } from "../services/adminActualidadService";
import { logger } from '../../../lib/logger';

export function useActualidadEditor(id: string | undefined) {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [topic, setTopic] = useState<Topic | null>(null);

    const [formData, setFormData] = useState<Partial<Topic>>({});
    const [questions, setQuestions] = useState<TopicQuestion[]>([]);
    const [tagsInput, setTagsInput] = useState("");
    const [actorsInput, setActorsInput] = useState("");

    const fetchTopic = useCallback(async () => {
        if (!id) return;
        setLoading(true);
        try {
            const data = await adminActualidadService.getAdminTopicById(id);
            if (data) {
                setTopic(data);
                setFormData({
                    title: data.title,
                    summary: data.summary,
                    impact_phrase: data.impact_phrase || (window as any).impact_quote,
                    category: data.category,
                    intensity: data.intensity,
                    relevance_chile: data.relevance_chile,
                    event_stage: data.event_stage,
                    topic_duration: data.topic_duration,
                    opinion_maturity: data.opinion_maturity,
                    status: data.status,
                    tags: data.tags,
                    actors: data.actors,
                });

                const sortedQ = [...(data.questions || [])].sort((a, b) => a.order - b.order);
                while (sortedQ.length < 3) {
                    const defaultTypes: QuestionType[] = ['scale_0_10', 'single_choice', 'single_choice_polar'];
                    sortedQ.push({
                        id: crypto.randomUUID(),
                        order: sortedQ.length + 1,
                        text: "",
                        type: defaultTypes[sortedQ.length] || 'single_choice',
                        options: []
                    });
                }
                setQuestions(sortedQ.slice(0, 3));
                setTagsInput(data.tags?.join(", ") || "");
                setActorsInput(data.actors?.join(", ") || "");
            }
        } catch (err) {
            logger.error("Error fetching topic", { domain: 'actualidad_editorial', origin: 'useActualidadEditor', action: 'fetch_topic', state: 'failed' }, err);
        } finally {
            setLoading(false);
        }
    }, [id]);

    useEffect(() => {
        fetchTopic();
    }, [fetchTopic]);

    const handleTagsChange = (val: string) => {
        setTagsInput(val);
        setFormData(prev => ({ ...prev, tags: val.split(',').map(t => t.trim()).filter(Boolean) }));
    };

    const handleActorsChange = (val: string) => {
        setActorsInput(val);
        setFormData(prev => ({ ...prev, actors: val.split(',').map(a => a.trim()).filter(Boolean) }));
    };

    const handleQuestionChange = (orderIdx: number, field: string, value: any) => {
        setQuestions(prev => {
            const newQ = [...prev];
            newQ[orderIdx] = { ...newQ[orderIdx], [field]: value };
            return newQ;
        });
    };

    const handleQuestionOptionAdd = (orderIdx: number) => {
        setQuestions(prev => {
            const newQ = [...prev];
            newQ[orderIdx].options = [...(newQ[orderIdx].options || []), "Nueva Opción"];
            return newQ;
        });
    };

    const handleQuestionOptionChange = (orderIdx: number, optIdx: number, value: string) => {
        setQuestions(prev => {
            const newQ = [...prev];
            const newOpts = [...(newQ[orderIdx].options || [])];
            newOpts[optIdx] = value;
            newQ[orderIdx].options = newOpts;
            return newQ;
        });
    };

    const handleQuestionOptionRemove = (orderIdx: number, optIdx: number) => {
        setQuestions(prev => {
            const newQ = [...prev];
            const newOpts = [...(newQ[orderIdx].options || [])];
            newOpts.splice(optIdx, 1);
            newQ[orderIdx].options = newOpts;
            return newQ;
        });
    };

    const validateForm = () => {
        if (!formData.title?.trim()) return "El título es obligatorio.";
        if (!formData.summary?.trim()) return "El resumen neutral es obligatorio.";
        if (!formData.category) return "Debe tener una categoría.";

        for (let i = 0; i < 3; i++) {
            const q = questions[i];
            if (!q.text.trim()) return `La Pregunta ${i + 1} debe tener texto.`;
            if (q.type === 'single_choice' || q.type === 'single_choice_polar') {
                if (!q.options || q.options.length < 2) return `La Pregunta ${i + 1} (${q.type}) requiere al menos 2 opciones.`;
                if (q.options.some(opt => !opt.trim())) return `La Pregunta ${i + 1} tiene opciones vacías.`;
            }
        }
        return null;
    };

    const handleSave = async (silent = false) => {
        if (!topic || !id) return false;

        const err = validateForm();
        if (err) {
            if (!silent) alert(err);
            return false;
        }

        setSaving(true);
        try {
            const updates = { ...formData };
            await adminActualidadService.updateTopicEditorialData(id, updates, true);
            await adminActualidadService.updateTopicQuestions(id, questions);

            setTopic(prev => prev ? { ...prev, ...formData, admin_edited: true } as Topic : null);

            if (!silent) alert("Cambios guardados exitosamente.");
            return true;
        } catch (e) {
            logger.error("Error al guardar cambios de actualidad", { domain: 'actualidad_editorial', origin: 'useActualidadEditor', action: 'save_topic', state: 'failed', topic_id: id }, e);
            if (!silent) alert("Error al guardar cambios.");
            return false;
        } finally {
            setSaving(false);
        }
    };

    const handleStatusChange = async (newStatus: TopicStatus) => {
        if (!id || !topic) return;

        if (newStatus === 'published' || newStatus === 'approved') {
            const saved = await handleSave(true);
            if (!saved) {
                alert("Corrige los errores del formulario antes de transicionar estado.");
                return;
            }
        }

        setSaving(true);
        try {
            const res = await adminActualidadService.updateTopicStatus(id, newStatus);
            if (res.success) {
                setTopic(prev => prev ? { ...prev, status: newStatus } : null);
                setFormData(prev => ({ ...prev, status: newStatus }));
                if (newStatus === 'published') {
                    navigate('/admin/actualidad');
                }
            } else {
                alert(res.error || "No se pudo cambiar el estado.");
            }
        } catch (e) {
            logger.error("Error changing topic status", { domain: 'actualidad_editorial', origin: 'useActualidadEditor', action: 'change_status', state: 'failed', topic_id: id, new_status: newStatus }, e);
        } finally {
            setSaving(false);
        }
    };

    return {
        topic,
        formData,
        setFormData,
        questions,
        tagsInput,
        actorsInput,
        loading,
        saving,
        handleTagsChange,
        handleActorsChange,
        handleQuestionChange,
        handleQuestionOptionAdd,
        handleQuestionOptionChange,
        handleQuestionOptionRemove,
        handleSave,
        handleStatusChange,
        navigate
    };
}

import { useState, useEffect, useMemo, useCallback } from 'react';
import { adminInvitesService, InviteRow, RedemptionRow } from '../services/adminInvitesService';
import { supabase } from '../../../supabase/client';

export type StatusFilterType = 'all' | 'pending' | 'in_use' | 'abandoned' | 'revoked';

export function useAdminInvites() {
    const [tab, setTab] = useState<'invites' | 'redemptions'>('invites');
    const [invites, setInvites] = useState<InviteRow[]>([]);
    const [redemptions, setRedemptions] = useState<RedemptionRow[]>([]);
    const [loading, setLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState<string | null>(null);
    const [prefix, setPrefix] = useState('OP');
    const [statusFilter, setStatusFilter] = useState<StatusFilterType>('all');
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedInvites, setSelectedInvites] = useState<Set<string>>(new Set());
    const [confirmAction, setConfirmAction] = useState<'active' | 'revoked' | 'delete' | null>(null);
    const [confirmRowAction, setConfirmRowAction] = useState<{ id: string, action: 'active' | 'revoked' | 'delete' } | null>(null);
    const [waDrafts, setWaDrafts] = useState<Record<string, { phone: string; isSending: boolean; statusMsg?: string }>>({});
    const [sortConfig, setSortConfig] = useState<{ key: keyof InviteRow; direction: 'asc' | 'desc' } | null>(null);

    const handleSort = (key: keyof InviteRow) => {
        let direction: 'asc' | 'desc' = 'desc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'desc') {
            direction = 'asc';
        }
        setSortConfig({ key, direction });
    };

    const sortedInvites = useMemo(() => {
        const sortableItems = [...invites];

        if (sortConfig !== null) {
            sortableItems.sort((a, b) => {
                const aValue = a[sortConfig.key];
                const bValue = b[sortConfig.key];

                if (aValue === null || aValue === undefined) return sortConfig.direction === 'asc' ? -1 : 1;
                if (bValue === null || bValue === undefined) return sortConfig.direction === 'asc' ? 1 : -1;

                if (aValue < bValue) {
                    return sortConfig.direction === 'asc' ? -1 : 1;
                }
                if (aValue > bValue) {
                    return sortConfig.direction === 'asc' ? 1 : -1;
                }
                return 0;
            });
        } else {
             const priority: Record<string, number> = {
                'used': 1,
                'active': 2,
                'revoked': 3
            };

            sortableItems.sort((a, b) => {
                const pA = priority[a.status] || 99;
                const pB = priority[b.status] || 99;

                if (pA !== pB) return pA - pB;

                return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
            });
        }
        return sortableItems;
    }, [invites, sortConfig]);

    const updateWaDraft = (id: string, updates: Partial<{ phone: string; isSending: boolean; statusMsg?: string }>) => {
        setWaDrafts(prev => ({
            ...prev,
            [id]: { ...(prev[id] || { phone: '', isSending: false }), ...updates }
        }));
    };

    const handleSendWhatsApp = async (invite: InviteRow) => {
        const draft = waDrafts[invite.id];
        if (!draft?.phone || !draft.phone.startsWith('+')) {
            alert('Por favor ingresa un teléfono válido con formato +... (ej: +56912345678)');
            return;
        }

        updateWaDraft(invite.id, { isSending: true, statusMsg: undefined });
        try {
            const res = await adminInvitesService.sendWhatsAppInvite(invite.id, draft.phone);
            if (res.success) {
                updateWaDraft(invite.id, { isSending: false, statusMsg: 'Enviado ✅' });
                setInvites(prev => prev.map(i => i.id === invite.id ? {
                    ...i,
                    whatsapp_phone: draft.phone,
                    whatsapp_status: 'sent',
                    whatsapp_sent_at: new Date().toISOString()
                } : i));
            } else {
                const detailObj = res.detail as { error?: { message?: string } } | undefined;
                const detailMsg = detailObj?.error?.message || res.error || 'Fallo desconocido';
                updateWaDraft(invite.id, { isSending: false, statusMsg: `Error: ${detailMsg.substring(0, 100)}` });
            }
        } catch (err: unknown) {
            updateWaDraft(invite.id, { isSending: false, statusMsg: `Error: ${(err as Error).message}` });
        }
    };

    const fetchInvites = useCallback(async () => {
        setLoading(true);
        setErrorMsg(null);
        try {
            const data = await adminInvitesService.listInvites(statusFilter, searchTerm);
            setInvites(data);
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || 'Error fetching invites');
        } finally {
            setLoading(false);
        }
    }, [statusFilter, searchTerm]);

    const fetchRedemptions = useCallback(async () => {
        setLoading(true);
        setErrorMsg(null);
        try {
            const data = await adminInvitesService.listRedemptions(200);
            setRedemptions(data);
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || 'Error fetching redemptions');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        setSelectedInvites(new Set());
        setConfirmAction(null);
        setConfirmRowAction(null);
        if (tab === 'invites') fetchInvites();
        else fetchRedemptions();
    }, [tab, statusFilter, fetchInvites, fetchRedemptions]);

    const handleGenerate = async () => {
        setLoading(true);
        setErrorMsg(null);
        try {
            await adminInvitesService.generateInvites(10, prefix);
            await fetchInvites();
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || 'Error generating invites');
        } finally {
            setLoading(false);
        }
    };

    const handleStatusChange = async (inviteId: string, _currentStatus: string, action: 'revoked' | 'active' | 'delete') => {
        setLoading(true);
        setErrorMsg(null);
        setConfirmRowAction(null);
        try {
            if (action === 'delete') {
                await adminInvitesService.deleteInvite(inviteId);
                setInvites(invites.filter((i) => i.id !== inviteId));
            } else {
                const { error } = await (supabase as any).rpc('admin_set_invitation_status', {
                    p_invite_id: inviteId,
                    p_status: action,
                });
                if (error) throw error;
                setInvites(invites.map((i) => i.id === inviteId ? { ...i, status: action } : i));
            }
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || `Error updating invite status to ${action}`);
        } finally {
            setLoading(false);
        }
    };

    const handleCopyActive = async () => {
        const activeCodes = invites
            .filter((i) => i.status === 'active')
            .map((i) => i.code)
            .join('\n');

        if (!activeCodes) {
            setErrorMsg('No active codes to copy');
            return;
        }

        try {
            await navigator.clipboard.writeText(activeCodes);
            alert('Códigos copiados al portapapeles!');
        } catch (err) {
            setErrorMsg('Failed to copy to clipboard');
        }
    };

    const toggleSelectAll = () => {
        if (selectedInvites.size === invites.length && invites.length > 0) {
            setSelectedInvites(new Set());
        } else {
            setSelectedInvites(new Set(invites.map(i => i.id)));
        }
    };

    const toggleSelect = (id: string) => {
        const newSet = new Set(selectedInvites);
        if (newSet.has(id)) newSet.delete(id);
        else newSet.add(id);
        setSelectedInvites(newSet);
    };

    const handleBulkAction = async (action: 'active' | 'revoked' | 'delete') => {
        if (selectedInvites.size === 0) return;

        setLoading(true);
        setErrorMsg(null);
        setConfirmAction(null);
        try {
            const promises = Array.from(selectedInvites).map(async (inviteId) => {
                if (action === 'delete') {
                    return adminInvitesService.deleteInvite(inviteId);
                } else {
                    return (supabase as any).rpc('admin_set_invitation_status', {
                        p_invite_id: inviteId,
                        p_status: action,
                    });
                }
            });

            await Promise.all(promises);

            await fetchInvites();
            setSelectedInvites(new Set());
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || `Error procesando acción masiva`);
        } finally {
            setLoading(false);
        }
    };

    const stats = useMemo(() => {
        const total = invites.length;
        const used = invites.filter(i => i.status === 'used').length;
        const active = invites.filter(i => i.status === 'active').length;
        // Consider abandonment as those sent via WA but not used, or explicitly with abandoned status
        const abandoned = invites.filter(i => i.status === 'abandoned' || (i.status === 'active' && i.whatsapp_status === 'sent')).length;
        const conversionRate = total > 0 ? (used / total) * 100 : 0;

        return { total, used, active, abandoned, conversionRate };
    }, [invites]);

    return {
        tab, setTab,
        invites, redemptions,
        loading, errorMsg,
        prefix, setPrefix,
        statusFilter, setStatusFilter,
        searchTerm, setSearchTerm,
        selectedInvites, setSelectedInvites,
        confirmAction, setConfirmAction,
        confirmRowAction, setConfirmRowAction,
        waDrafts, sortConfig,
        handleSort, sortedInvites,
        updateWaDraft, handleSendWhatsApp,
        fetchInvites, fetchRedemptions,
        handleGenerate, handleStatusChange,
        handleCopyActive, toggleSelectAll, toggleSelect,
        handleBulkAction, stats
    };
}

import { useParams } from "react-router-dom";
import { 
  ArrowLeft, Save, CheckCircle, UploadCloud, Archive, XCircle, 
  AlertCircle, Globe, Clock, Edit2, Activity, FileEdit
} from "lucide-react";
