/**
 * Validaciones Mínimas Requeridas del Payload IA (Bloque 1)
 */
export const validateAiTopicPayload = (payload: unknown): string[] => {
  const errors: string[] = [];

  if (!payload || typeof payload !== 'object') {
    return ['Payload es nulo o no es un objeto'];
  }

  const p = payload as Record<string, unknown>;

  // título obligatorio
  if (!p.title || typeof p.title !== 'string' || p.title.trim().length === 0) {
    errors.push('title es obligatorio y no puede estar vacío');
  }

  // summary obligatorio
  if (!p.summary || typeof p.summary !== 'string' || p.summary.trim().length === 0) {
    errors.push('summary es obligatorio y no puede estar vacío');
  }

  // impact_phrase obligatorio
  if (!p.impact_phrase || typeof p.impact_phrase !== 'string' || p.impact_phrase.trim().length === 0) {
    errors.push('impact_phrase (Cita de impacto) es obligatoria');
  }

  // category válida
  const validCategories: TopicCategory[] = [
    'País', 'Economía', 'Ciudad / Vida diaria', 'Marcas y Consumo', 'Deportes y Cultura', 'Tendencias y Sociedad'
  ];
  if (!validCategories.includes(p.category as TopicCategory)) {
    errors.push(`category inválida: ${p.category}`);
  }

  // source_url obligatorio
  if (!p.source_url || typeof p.source_url !== 'string' || p.source_url.trim().length === 0) {
    errors.push('source_url es obligatorio y no puede estar vacío');
  }

  // limits: intensity (1-3)
  if (typeof p.intensity !== 'number' || p.intensity < 1 || p.intensity > 3) {
    errors.push('intensity debe ser un número entre 1 y 3');
  }

  // questions debe tener exactamente 3 preguntas
  if (!Array.isArray(p.questions) || p.questions.length !== 3) {
    errors.push('questions debe ser un arreglo de exactamente 3 preguntas');
  } else {
    const orders = new Set<number>();
    (p.questions as unknown[]).forEach((q: any, i: number) => {
      if (!q || typeof q !== 'object') {
        errors.push(`Pregunta [${i}] no es un objeto válido`);
        return;
      }

      // order, text, type requeridos
      if (typeof q.order !== 'number') {
        errors.push(`Pregunta [${i}] le falta 'order' numerico`);
      } else {
        if (orders.has(q.order)) errors.push(`Pregunta [${i}] tiene un 'order' duplicado: ${q.order}`);
        orders.add(q.order);
      }

      if (!q.text || typeof q.text !== 'string' || q.text.trim().length === 0) {
        errors.push(`Pregunta [${i}] le falta 'text' o está vacío`);
      }

      const validTypes: QuestionType[] = ['yes_no', 'single_choice', 'single_choice_polar', 'scale_5', 'scale_0_10'];
      if (!validTypes.includes(q.type as QuestionType)) {
        errors.push(`Pregunta [${i}] tiene tipo inválido: ${q.type}`);
      }

      // Validar que existan opciones si el tipo lo requiere
      if (['single_choice', 'single_choice_polar'].includes(q.type as string)) {
        if (!Array.isArray(q.options) || q.options.length < 2) {
          errors.push(`Pregunta [${i}] tipo ${q.type} requiere arreglo de options con al menos 2 ítemes`);
        } else {
          if ((q.options as unknown[]).some((opt: any) => typeof opt !== 'string' || opt.trim() === '')) {
            errors.push(`Pregunta [${i}] contiene opciones vacías o inválidas`);
          }
        }
      }
    });
  }

  return errors;
};

import { supabase } from '../../supabase/client';

type TelemetrySeverity = 'info' | 'warn' | 'error';

type QueuedEvent = {
    eventName: string;
    severity: TelemetrySeverity;
    context: Record<string, unknown>;
    clientEventId?: string | null;
    ts: number;
};

const LS_QUEUE_KEY = 'opina_telemetry_queue_v1';
const MAX_QUEUE = 50;

function readQueue(): QueuedEvent[] {
    try {
        const raw = localStorage.getItem(LS_QUEUE_KEY);
        if (!raw) return [];
        const parsed = JSON.parse(raw);
        if (!Array.isArray(parsed)) return [];
        return (parsed as QueuedEvent[]).slice(0, MAX_QUEUE);
    } catch {
        return [];
    }
}

function writeQueue(q: QueuedEvent[]) {
    try {
        localStorage.setItem(LS_QUEUE_KEY, JSON.stringify(q.slice(0, MAX_QUEUE)));
    } catch {
        // noop
    }
}

function enqueue(ev: QueuedEvent) {
    const q = readQueue();
    q.push(ev);
    writeQueue(q.slice(-MAX_QUEUE));
}

function isAuthOrPermError(err: unknown): boolean {
    const error = err as { message?: string; code?: string } | null;
    const msg = String(error?.message || '').toLowerCase();
    const code = String(error?.code || '').toLowerCase();
    return (
        msg.includes('permission denied') ||
        msg.includes('jwt') ||
        msg.includes('not authenticated') ||
        code === '42501'
    );
}

async function sendOne(ev: QueuedEvent) {
    const env = (import.meta as { env?: Record<string, string> }).env;
    const appVersion = env?.VITE_APP_VERSION ?? 'unknown';
    const userAgent = typeof navigator !== 'undefined' ? navigator.userAgent : 'unknown';

    let safeContext: Record<string, unknown> = ev.context || {};
    try {
        const strContext = JSON.stringify(safeContext);
        if (strContext.length > 4000) safeContext = { truncated: true, reason: 'payload_too_large' };
    } catch {
        safeContext = { parse_error: true };
    }

    const { error } = await (supabase.rpc as any)('log_app_event', {
        p_event_name: ev.eventName,
        p_severity: ev.severity,
        p_context: safeContext,
        p_client_event_id: ev.clientEventId || null,
        p_app_version: appVersion,
        p_user_agent: userAgent
    });

    if (error) throw error;
}

async function flushQueueBestEffort() {
    const q = readQueue();
    if (!q.length) return;

    const remaining: QueuedEvent[] = [];
    for (const ev of q) {
        try {
            await sendOne(ev);
        } catch (err: unknown) {
            // Si aún no hay permisos/sesión, paramos y dejamos el resto.
            if (isAuthOrPermError(err)) {
                remaining.push(ev, ...q.slice(q.indexOf(ev) + 1));
                break;
            }
            // Si fue error de red, también paramos (no insistir en loop)
            remaining.push(ev, ...q.slice(q.indexOf(ev) + 1));
            break;
        }
    }
    writeQueue(remaining);
}

export const telemetryService = {
    /**
     * Log de evento (no PII). Si no hay sesión/permisos, se encola en localStorage y se flushea luego.
     */
    logEvent: (
        eventName: string,
        severity: TelemetrySeverity = 'info',
        context?: Record<string, unknown>,
        clientEventId?: string
    ): void => {
        try {
            // Flush previo (no bloqueante)
            flushQueueBestEffort().catch(() => void 0);

            const ev: QueuedEvent = {
                eventName,
                severity,
                context: context || {},
                clientEventId: clientEventId || null,
                ts: Date.now()
            };

            // Fire and forget
            sendOne(ev).catch((err: unknown) => {
                // Si no hay permisos/sesión, encolamos para flush posterior
                if (isAuthOrPermError(err)) {
                    enqueue(ev);
                    return;
                }
                // Silenciar errores (offline, adblockers)
                const message = (err as { message?: string })?.message || String(err);
                console.debug('[Telemetry] Failed to log event:', message);
            });

        } catch (err) {
            console.debug('[Telemetry] Exception logging event local phase:', err);
        }
    },

    flush: (): void => {
        flushQueueBestEffort().catch(() => void 0);
    }
};

import { useEffect, useRef } from 'react';
import { supabase } from '../supabase/client';
import { getAnonId } from '../features/auth/services/anonService';

/**
 * useSessionTracker
 * 
 * A lightweight hook that mounts at the App array root to track
 * user sessions and time spent on the platform. It calculates time
 * delta and flushes it to the database when the tab becomes hidden
 * or unloads.
 */
export function useSessionTracker() {
    const isFirstMount = useRef(true);
    const lastFlushTime = useRef<number>(Date.now());

    useEffect(() => {
        /**
         * Internal function to call the tracker RPC silently.
         */
        const flushSession = async (secondsSpent: number, isNewSession: boolean) => {
            try {
                // In a real-world edge case anon_id may not be ready immediately, 
                // but getting it from localStorage is synchronous enough.
                let anonId: string | null = null;
                try {
                    anonId = await getAnonId();
                } catch {
                    // ignore
                }

                await (supabase.rpc as any)('track_user_session', {
                    p_anon_id: anonId || null,
                    p_seconds_spent: secondsSpent,
                    p_is_new_session: isNewSession
                });
            } catch (err) {
                // Silently fail, analytics shouldn't crash the app
                console.warn('Session tracker flush failed', err);
            }
        };

        // Report that a new session has started (page load)
        if (isFirstMount.current) {
            isFirstMount.current = false;
            flushSession(0, true);
        }

        const handleVisibilityChange = () => {
            if (document.visibilityState === 'hidden') {
                // Tab is hidden, paused or closing. Flush accrued time.
                const now = Date.now();
                const accruedMs = now - lastFlushTime.current;
                const secondsSpent = Math.floor(accruedMs / 1000);

                if (secondsSpent > 0) {
                    flushSession(secondsSpent, false);
                    lastFlushTime.current = now;
                }
            } else if (document.visibilityState === 'visible') {
                // Tab is active again. Reset the flush timer.
                lastFlushTime.current = Date.now();
            }
        };

        const handleBeforeUnload = () => {
            // Final flush just in case (Browser may or may not guarantee this request goes out)
            const now = Date.now();
            const accruedMs = now - lastFlushTime.current;
            const secondsSpent = Math.floor(accruedMs / 1000);

            if (secondsSpent > 0) {
                flushSession(secondsSpent, false);
            }
        };

        document.addEventListener('visibilitychange', handleVisibilityChange);
        window.addEventListener('beforeunload', handleBeforeUnload);

        return () => {
            document.removeEventListener('visibilitychange', handleVisibilityChange);
            window.removeEventListener('beforeunload', handleBeforeUnload);
        };
    }, []);
}

